#include <bits/stdc++.h>
using namespace std;

const int N=260;

int c,T,n,m,a[N],b[N];

int main(){
    scanf("%d%d",&c,&T);
    while(T--){
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
            scanf("%d",&a[i]);
        for(int i=1;i<=m;i++)
            scanf("%d",&b[i]);
        if(c<=2){
            deque<int> q;
            bool f=true;
            for(int i=0;i<1<<n-m;i++){
                for(int j=1;j<=n;j++)
                    q.push_back(a[j]);
                for(int j=0;j<n-m;j++){
                    int u,v;
                    if((i>>j)&1){
                        u=q.back();
                        q.pop_back();
                        v=q.back();
                        q.pop_back();
                        q.push_front(u^v);
                    }else{
                        u=q.front();
                        q.pop_front();
                        v=q.front();
                        q.pop_front();
                        q.push_back(u^v);
                    }
                }
                bool flag=true;
                for(int j=1;j<=m;j++){
                    int u=q.front();
                    q.pop_front();
                    if(u!=b[j])
                        flag=false;
                }
                if(flag){
                    f=false;
                    puts("Yes");
                    for(int j=0;j<n-m;j++)
                        printf("%d ",((i>>j)&1)+1);
                    puts("");
                    break;
                }
            }
            if(f)
                puts("No");
        }else{
            int sum=0;
            for(int i=1;i<=n;i++)
                sum^=a[i];
            if(sum==b[1]){
                puts("Yes");
                for(int i=1;i<n;i++)
                    printf("1 ");
                puts("");
            }else
                puts("No");
        }
    }
    return 0;
}
